"""REFUGIO local experiment policy.

This file is for local simulator iteration only. It starts from the team's
prior v2 prioritized-reservation flow policy.
"""

from __future__ import annotations

from collections import deque

from warehouse_api import Action, CellType, Observation, Position

_DIRS: tuple[tuple[Action, int, int], ...] = (
    (Action.RIGHT, 1, 0),
    (Action.LEFT, -1, 0),
    (Action.DOWN, 0, 1),
    (Action.UP, 0, -1),
)
_DIR_IDX = {action: i for i, (action, _, _) in enumerate(_DIRS)}


def create_layout() -> dict[str, object]:
    shelves: list[list[int]] = []
    for y0 in range(3, 48, 4):
        for x0, x1 in ((3, 12), (15, 24), (27, 36), (39, 48)):
            for y in (y0, y0 + 1):
                for x in range(x0, x1 + 1):
                    shelves.append([x, y])
    return {"schema_version": 1, "shelves": shelves}


_W = 0
_WALK: list[bool] = []
_READY = False
_BASE: dict[Position, list[int]] = {}
_SHELF: dict[Position, list[int]] = {}
_CTICK = -1
_RES: set[Position] = set()
_LEFT: dict[Position, Position] = {}


def _init(grid: tuple[tuple[CellType, ...], ...]) -> None:
    global _W, _WALK, _READY
    if _READY:
        return
    _W = len(grid)
    walk = [False] * (_W * _W)
    for y in range(_W):
        row = grid[y]
        for x in range(_W):
            if 1 <= x <= 50 and 1 <= y <= 50 and row[x] == CellType.EMPTY:
                walk[y * _W + x] = True
    _WALK = walk
    _READY = True


def _bfs(sources: list[Position]) -> list[int]:
    width = _W
    dist = [-1] * (width * width)
    queue: deque[tuple[int, int]] = deque()
    for sx, sy in sources:
        if 0 <= sx < width and 0 <= sy < width and _WALK[sy * width + sx]:
            index = sy * width + sx
            if dist[index] != 0:
                dist[index] = 0
                queue.append((sx, sy))
    while queue:
        x, y = queue.popleft()
        next_distance = dist[y * width + x] + 1
        for _, dx, dy in _DIRS:
            nx, ny = x + dx, y + dy
            if 0 <= nx < width and 0 <= ny < width:
                next_index = ny * width + nx
                if _WALK[next_index] and dist[next_index] == -1:
                    dist[next_index] = next_distance
                    queue.append((nx, ny))
    return dist


def _drop(base: Position) -> Position:
    x, y = base
    if y == 0:
        return (x, 1)
    if y == _W - 1:
        return (x, _W - 2)
    if x == 0:
        return (1, y)
    return (_W - 2, y)


def _base_field(drop: Position) -> list[int]:
    field = _BASE.get(drop)
    if field is None:
        field = _bfs([drop])
        _BASE[drop] = field
    return field


def _shelf_field(target: Position) -> list[int]:
    field = _SHELF.get(target)
    if field is None:
        tx, ty = target
        field = _bfs([(tx + 1, ty), (tx - 1, ty), (tx, ty + 1), (tx, ty - 1)])
        _SHELF[target] = field
    return field


def act(observation: Observation) -> Action:
    global _CTICK, _RES, _LEFT
    _init(observation.grid)
    width = _W
    px, py = observation.position

    if not observation.carrying_item:
        target = observation.target_item_position
        if abs(px - target[0]) + abs(py - target[1]) == 1:
            return Action.PICKUP
        field = _shelf_field(target)
    else:
        drop = _drop(observation.base_position)
        if observation.position == drop:
            return Action.DROP
        field = _base_field(drop)

    here = field[py * width + px]

    if observation.tick != _CTICK:
        _CTICK = observation.tick
        _RES = set()
        _LEFT = {}

    pos = (px, py)
    occupied_cells = set(observation.all_robot_positions.values())
    occupied_cells.discard(pos)

    mix = (observation.robot_id * 2654435761 + observation.tick * 40503) & 0xFFFF

    candidates: list[tuple[int, int, int, Action, Position]] = []
    for action, dx, dy in _DIRS:
        nx, ny = px + dx, py + dy
        if not (0 <= nx < width and 0 <= ny < width) or not _WALK[ny * width + nx]:
            continue
        next_distance = field[ny * width + nx]
        if next_distance < 0:
            continue
        rank = 0 if next_distance < here else (1 if next_distance == here else 2)
        tie_break = (mix * 31 + _DIR_IDX[action] * 7) & 0xFFFF
        candidates.append((rank, next_distance, tie_break, action, (nx, ny)))

    candidates.sort(key=lambda candidate: (candidate[0], candidate[1], candidate[2]))
    for _rank, _next_distance, _tie_break, action, cell in candidates:
        if cell in _RES:
            continue
        if cell in occupied_cells and not (cell in _LEFT and _LEFT[cell] != pos):
            continue
        _RES.add(cell)
        _LEFT[pos] = cell
        return action

    _RES.add(pos)
    return Action.WAIT


