def _base_entry(bx: int, by: int) -> tuple[int, int]:
    if bx == 0:
        return (1, by)
    if bx == GRID - 1:
        return (GRID - 2, by)
    if by == 0:
        return (bx, 1)
    return (bx, GRID - 2)


def _adjacent(a: Position, b: Position) -> bool:
    return abs(a[0] - b[0]) + abs(a[1] - b[1]) == 1


class _SotaWorld:
    __slots__ = ("dist_cache", "nbrs", "passable")

    def __init__(self, grid: tuple[tuple[CellType, ...], ...]) -> None:
        self.passable = np.zeros(GRID * GRID, dtype=bool)
        for y in range(WALK_MIN, WALK_MAX + 1):
            row = grid[y]
            for x in range(WALK_MIN, WALK_MAX + 1):
                if row[x] == CellType.EMPTY:
                    self.passable[_node(x, y)] = True

        nbrs: dict[int, tuple[tuple[Action, int], ...]] = {}
        for y in range(WALK_MIN, WALK_MAX + 1):
            for x in range(WALK_MIN, WALK_MAX + 1):
                n = _node(x, y)
                if not self.passable[n]:
                    continue
                candidates: list[tuple[Action, int]] = []
                for action, dx, dy in _SOTA_DIRS:
                    nx, ny = x + dx, y + dy
                    if WALK_MIN <= nx <= WALK_MAX and WALK_MIN <= ny <= WALK_MAX:
                        m = _node(nx, ny)
                        if self.passable[m]:
                            candidates.append((action, m))
                nbrs[n] = tuple(candidates)
        self.nbrs = nbrs
        self.dist_cache: dict[tuple[object, ...], np.ndarray] = {}

    def _bfs(self, sources: list[int]) -> np.ndarray:
        dist = np.full(GRID * GRID, INF, dtype=np.int32)
        queue: deque[int] = deque()
        for source in sources:
            if self.passable[source] and dist[source] != 0:
                dist[source] = 0
                queue.append(source)
        while queue:
            current = queue.popleft()
            next_distance = int(dist[current]) + 1
            for _action, neighbor in self.nbrs[current]:
                if dist[neighbor] > next_distance:
                    dist[neighbor] = next_distance
                    queue.append(neighbor)
        return dist

    def base_field(self, entry_node: int) -> np.ndarray:
        key = ("B", entry_node)
        field = self.dist_cache.get(key)
        if field is None:
            field = self._bfs([entry_node])
            self.dist_cache[key] = field
        return field

    def shelf_field(self, shelf: Position) -> np.ndarray:
        key = ("S", shelf)
        field = self.dist_cache.get(key)
        if field is None:
            sx, sy = shelf
            sources: list[int] = []
            for _action, dx, dy in _SOTA_DIRS:
                nx, ny = sx + dx, sy + dy
                if WALK_MIN <= nx <= WALK_MAX and WALK_MIN <= ny <= WALK_MAX:
                    candidate = _node(nx, ny)
                    if self.passable[candidate]:
                        sources.append(candidate)
            field = self._bfs(sources)
            self.dist_cache[key] = field
        return field


